    /// Epistemic confidence (INV-FERR-063). NOT Optional — every
    /// transaction has a provenance. Default: Observed.
    pub provenance: ProvenanceType,
    /// Store fingerprint BEFORE this transaction (INV-FERR-074/D17).
    /// Included in the signing message as a state commitment.
    /// Zero for unsigned transactions or when fingerprint not yet computed.
    pub store_fingerprint: [u8; 32],
}

impl TransactContext<'_> {
    /// Minimal context for tests. No frontier, no signing, Observed provenance.
    #[cfg(any(test, feature = "test-utils"))]
    pub fn minimal(tx_id: TxId) -> Self {
        Self {
            tx_id,
            frontier: None,
            signing: None,
            provenance: ProvenanceType::Observed,
            store_fingerprint: [0u8; 32],
        }
    }
}

// MODIFIED: Store::transact signature
impl Store {
    /// Was: pub fn transact(&mut self, transaction: Transaction<Committed>, tx_id: TxId)
    /// Now: takes TransactContext (D18)
    pub fn transact(
        &mut self,
        transaction: Transaction<Committed>,
        ctx: TransactContext<'_>,
    ) -> Result<TxReceipt, FerraError> {
        let datoms = transaction.datoms().to_vec();
        let agent = transaction.agent();
        drop(transaction);

        if datoms.is_empty() {
            return Err(FerraError::EmptyTransaction);
        }

        self.epoch = self.epoch.checked_add(1)
            .ok_or_else(|| FerraError::InvariantViolation {
                invariant: "INV-FERR-007".to_string(),
                details: "epoch counter overflow".to_string(),
            })?;

        let mut all_datoms = stamp_datoms(datoms, ctx.tx_id);

        // D16: TxId-based entity (replaces epoch-based)
        let tx_entity = tx_entity_from_txid(ctx.tx_id);

        // Existing metadata: tx/time + tx/agent
        all_datoms.extend(create_tx_metadata(tx_entity, agent, ctx.tx_id));

        // NEW: federation metadata (predecessors + provenance + signing)
        all_datoms.extend(create_federation_metadata(
            tx_entity, ctx.tx_id, ctx.frontier, ctx.signing, ctx.provenance,
        ));

        crate::schema_evolution::evolve_schema(&mut self.schema, &all_datoms)?;

        self.promote();
        for datom in &all_datoms {
            if let super::StoreRepr::OrdMap { datoms, indexes } = &mut self.repr {
                datoms.insert(datom.clone());
                indexes.insert(datom);
            }
            self.live_apply(datom);
            // D17: update fingerprint incrementally
            let h = blake3::hash(&datom.canonical_bytes());
            self.fingerprint.iter_mut().zip(h.as_bytes())
                .for_each(|(a, b)| *a ^= b);
        }

        let receipt = TxReceipt { epoch: self.epoch, datoms: all_datoms };
        self.demote();
        Ok(receipt)
    }

    // MODIFIED: transact_test uses TransactContext::minimal
    #[cfg(any(test, feature = "test-utils"))]
    pub fn transact_test(
        &mut self,
        transaction: Transaction<Committed>,
    ) -> Result<TxReceipt, FerraError> {
        let agent = transaction.agent();
        let tx_id = TxId::with_agent(self.epoch.wrapping_add(1), 0, agent);
