use ed25519_dalek::SigningKey;
use crate::store::apply::TransactContext;

impl Database<Ready> {
    // EXISTING: pub fn transact(tx) — MODIFIED internally
    pub fn transact(&self, transaction: Transaction<Committed>) -> Result<TxReceipt, FerraError> {
        self.transact_inner(transaction, None)
    }

    // NEW: signed transact path (D15)
    /// Apply a signed transaction. The signing key is used to compute
    /// the Ed25519 signature after HLC tick provides the TxId.
    ///
    /// INV-FERR-051: Signed Transactions.
    /// ADR-FERR-031: Database-Layer Signing.
    ///
    /// The signing message is:
    ///   blake3(sorted_user_datoms ∥ tx_id ∥ sorted_predecessor_entity_ids
    ///          ∥ store_fingerprint ∥ signer_public_key)
    ///
    /// D19: Predecessor EntityIds (not TxIds) — read directly from stored Refs
    /// at verification time. D17: Store fingerprint = pre-transaction state.
    pub fn transact_signed(
        &self,
        transaction: Transaction<Committed>,
        signing_key: &SigningKey,
    ) -> Result<TxReceipt, FerraError> {
        self.transact_inner(transaction, Some(signing_key))
    }

    // PRIVATE: unified transact implementation
    fn transact_inner(
        &self,
        transaction: Transaction<Committed>,
        signing_key: Option<&SigningKey>,
    ) -> Result<TxReceipt, FerraError> {
        let write_slot = self.write_limiter.try_acquire()
            .ok_or(FerraError::Backpressure)?;
        let (guard, tx_id) = self.acquire_write_lock_and_tick()?;

        let agent = transaction.agent();  // Copy before move (AgentId is Copy)
        let frontier = self.frontier()?;

        // D17: read store fingerprint BEFORE transaction
        let current = self.current.load();
        let store_fingerprint = current.fingerprint;

        // D15: sign if key provided (tx_id is now known from HLC tick)
        let signing = if let Some(key) = signing_key {
            let user_datoms = transaction.datoms();
            // D19: predecessor EntityIds for signing message
            let mut pred_entity_ids: Vec<EntityId> = frontier.iter()
                .map(|(_, tid)| crate::store::apply::tx_entity_from_txid(*tid))
                .collect();
            pred_entity_ids.sort();

            let (sig, signer) = crate::signing::sign_transaction(
                user_datoms, tx_id, &pred_entity_ids, &store_fingerprint, key,
            );
            Some((sig, signer))
        } else {
            None
        };

        let ctx = TransactContext {
            tx_id,
            frontier: Some(&frontier),
            signing,
            provenance: ProvenanceType::Observed,  // default; override via builder if needed
            store_fingerprint,
        };

        let mut new_store = Store::clone(&current);
        let receipt = new_store.transact(transaction, ctx)?;
        let new_datoms = receipt.datoms().to_vec();

        self.write_wal(receipt.epoch(), &new_datoms)?;
        self.publish_and_check(new_store);

        // INV-FERR-061: advance frontier after successful transact
        {
            let mut f = self.frontier.lock()
                .map_err(|_| FerraError::InvariantViolation {
                    invariant: "INV-FERR-061".to_string(),
                    details: "frontier mutex poisoned during advance".to_string(),
                })?;
            f.advance(agent, tx_id);
        }

        #[cfg(feature = "release_bijection_check")]
        self.verify_bijection_canary()?;

        drop(guard);
        drop(write_slot);
        let _ = self.notify_observers(receipt.epoch(), &new_datoms);
        Ok(receipt)
    }
}

