## Pseudocode Contract

```rust
/// Structure-of-Arrays columnar store representation (spec/09 "Columnar Storage").
///
/// Each field is a contiguous array. Column scans touch only the relevant
/// field's memory, achieving 100% cache utilization vs 6% for AoS.
///
/// INV-FERR-076: positional content addressing — position i refers to the
/// datom (entities[i], attr_ids[i], values[i], tx_ids[i], ops[i]).
pub struct ColumnarStore {
    /// Entity IDs in EAVT order. 32 bytes × N, packed.
    entities: Vec<EntityId>,
    /// Interned attribute IDs (bd-fnod). 2 bytes × N.
    attr_ids: Vec<AttributeId>,
    /// Values. Tagged union, ~16 bytes × N.
    values: Vec<Value>,
    /// Transaction IDs. 28 bytes × N.
    tx_ids: Vec<TxId>,
    /// Assert/Retract. 1 BIT × N (not 1 byte).
    ops: BitVec<u64, Lsb0>,

    /// Number of datoms.
    len: usize,

    // --- Auxiliary structures (unchanged from PositionalStore) ---
    /// LIVE bitvector (INV-FERR-029).
    live_bits: SuccinctBitVec,       // bd-t84f: rank/select capable
    /// Chunk fingerprints (INV-FERR-079).
    chunk_fps: ChunkFingerprints,    // bd-0zfw
    /// Store fingerprint (INV-FERR-074).
    fingerprint: [u8; 32],
    /// Entity Bloom filter (INV-FERR-027).
    bloom: EntityBloom,
    /// CHD perfect hash (INV-FERR-027).
    entity_mph: OnceLock<Chd>,
    /// Permutation arrays (INV-FERR-073, OnceLock = lazy).
    perm_aevt: OnceLock<Vec<u32>>,
    perm_vaet: OnceLock<Vec<u32>>,
    perm_avet: OnceLock<Vec<u32>>,
}

impl ColumnarStore {
    /// Reconstruct a datom at position i. O(1).
    #[inline]
    pub fn datom_at(&self, i: usize) -> Datom {
        Datom::new(
            self.entities[i],
            intern.resolve(self.attr_ids[i]),  // u16 → &str → Attribute
            self.values[i].clone(),
            self.tx_ids[i],
            if self.ops[i] { Op::Assert } else { Op::Retract },
        )
    }

    /// Iterate only the entity column (e.g., for entity existence check).
    /// Touches 32N bytes instead of 130N.
    pub fn entity_column(&self) -> &[EntityId] { &self.entities }

    /// Iterate only the attribute column (e.g., for schema queries).
    /// Touches 2N bytes instead of 130N.
    pub fn attr_column(&self) -> &[AttributeId] { &self.attr_ids }
}
```

