// Actually — the more meaningful property is the NEGATIVE test: if we
// intentionally break the model (e.g., commit before fsync), does the
// existing recovery property catch it? The WAL ordering guarantee is
// already STRUCTURALLY ENFORCED by the state machine design.
//
// The useful addition: verify that crash-before-fsync NEVER produces
// phantom datoms in the recovered store:
Property::always(
    "inv_ferr_008_no_unfsynced_in_recovery",
    |_: &CrashRecoveryModel, state: &CrashRecoveryState| {
        if let Phase::Crashed { fsynced: false, pending } = &state.phase {
            // Crash before fsync: pending datoms must NOT be in WAL
            // (they weren't durable yet). If they're in WAL, recovery
            // would replay them — violating the ordering guarantee.
            pending.iter().all(|d| !state.wal.contains(d))
