pub fn deserialize_checkpoint_bytes(data: &[u8]) -> Result<Store, FerraError> {
    if data.len() < 4 {
        return Err(FerraError::CheckpointCorrupted {
            expected: "at least 4 bytes for checkpoint magic".to_string(),
            actual: format!("{} bytes", data.len()),
        });
    }
    match &data[..4] {
        b"CHKP" => deserialize_v2_bytes(data), // existing path, renamed
        b"CHK3" => v3::deserialize_v3_bytes(data),
        magic => Err(FerraError::CheckpointCorrupted {
            expected: "checkpoint magic CHKP or CHK3".to_string(),
            actual: format!("unknown magic {:?}", &magic[..4]),
        }),
    }
}
