## Pseudocode Contract

```rust
proptest! {
    #[test]
    fn inv_ferr_075_live_first_full_roundtrip(
        datoms in arb_datom_set_with_retractions(0..500),
    ) {
        let mut store = Store::genesis();
        for datom_batch in datoms {
            let tx = build_transaction(&store, datom_batch);
            store.transact_test(tx).unwrap();
        }

        let bytes = checkpoint::serialize_live_first_bytes(&store)
            .expect("serialize");
        let loaded = checkpoint::deserialize_checkpoint_bytes(&bytes)
            .expect("deserialize via dispatch");

        prop_assert_eq!(
            loaded.datom_set(), store.datom_set(),
            "INV-FERR-075: full round-trip must preserve datom set"
        );
        prop_assert_eq!(loaded.epoch(), store.epoch());
    }

    #[test]
    fn inv_ferr_075_live_first_partial_then_historical(
        datoms in arb_datom_set_with_retractions(0..500),
    ) {
        let mut store = Store::genesis();
        for datom_batch in datoms {
            let tx = build_transaction(&store, datom_batch);
            store.transact_test(tx).unwrap();
        }

        let bytes = checkpoint::serialize_live_first_bytes(&store)
            .expect("serialize");
        let partial = checkpoint::v3::deserialize_v3_live_first_partial(&bytes)
            .expect("partial load");

        // Partial store has <= full datoms
        prop_assert!(partial.store.len() <= store.len());

        // Full merge recovers everything
        let full = partial.load_historical();
        prop_assert_eq!(
            full.datom_set(), store.datom_set(),
            "INV-FERR-075: load_historical must recover full datom set"
        );
    }
}
```

