// --- ferratomic-verify proptest ---

proptest! {
    #[test]
    fn inv_ferr_027_mph_completeness(
        datoms in arb_datom_set(1..500),
    ) {
        let ps = PositionalStore::from_datoms(datoms.into_iter());
        let unique_eids = ps.unique_entity_ids();
        // Force MPH construction via entity_lookup
        for eid in &unique_eids {
            prop_assert!(
                ps.entity_lookup(eid).is_some(),
                "INV-FERR-027: entity_lookup must find every entity in the store"
            );
        }
    }

    #[test]
    fn inv_ferr_027_entity_lookup_correct_position(
        datoms in arb_datom_set(1..500),
    ) {
        let ps = PositionalStore::from_datoms(datoms.into_iter());
        for (i, datom) in ps.datoms().iter().enumerate() {
            let eid = datom.entity();
            let pos = ps.entity_lookup(&eid);
            // entity_lookup returns the FIRST datom position for this entity
            prop_assert!(pos.is_some());
            let p = pos.unwrap() as usize;
            prop_assert!(p <= i, "first position must be <= current position");
            prop_assert_eq!(ps.datom_at(pos.unwrap()).unwrap().entity(), eid);
        }
    }

    #[test]
    fn inv_ferr_027_entity_lookup_absent_rejected(
        datoms in arb_datom_set(1..200),
        absent_seed in 200u8..255u8,
    ) {
        let ps = PositionalStore::from_datoms(datoms.into_iter());
        let absent = EntityId::from_content(&[absent_seed, 0xFF, 0xFF]);
        if ps.datoms().iter().all(|d| d.entity() != absent) {
            prop_assert_eq!(
                ps.entity_lookup(&absent), None,
                "INV-FERR-027: absent entity must return None"
            );
        }
    }
}

