```rust
impl Transaction<Committed> {
    /// Consume the transaction and yield the owned datom vector.
    pub fn into_datoms(self) -> Vec<Datom> {
        self.datoms
    }
    // datoms(&self) -> &[Datom] UNCHANGED — kept for callers that borrow.
}

// In Store::transact (apply.rs):
// REORDERED — agent() must be read BEFORE into_datoms() consumes self:
// Was:
//   let datoms = transaction.datoms().to_vec();
//   let agent = transaction.agent();
//   drop(transaction);
// Now:
let agent = transaction.agent();         // read agent FIRST
let datoms = transaction.into_datoms();  // THEN consume (no clone)

// In Database::transact (db/transact.rs):
// Was: let new_datoms = receipt.datoms().to_vec();
// Now: use receipt.datoms() directly (borrow, not clone):
let payload = bincode::serialize(receipt.datoms())?;  // for WAL
self.wal.append_raw(receipt.epoch(), &payload)?;
// ... observer notification uses receipt.datoms() too
```

