use std::collections::BTreeMap;
use std::sync::Arc;
use super::db::{Database, Ready};
use ferratom::SignedTransactionBundle;

pub struct LocalTransport {
    db: Arc<Database<Ready>>,
}

impl LocalTransport {
    #[must_use]
    pub fn new(db: Arc<Database<Ready>>) -> Self { todo!() }
}

impl Transport for LocalTransport {
    fn fetch_datoms<'a>(
        &'a self,
        filter: &'a DatomFilter,
    ) -> Pin<Box<dyn Future<Output = Result<Vec<Datom>, FerraError>> + Send + 'a>> {
        let snapshot = self.db.snapshot();
        Box::pin(std::future::ready(Ok(
            snapshot.datoms()
                .filter(|d| filter.matches(d))
                .cloned()
                .collect()
        )))
    }

    fn fetch_signed_transactions<'a>(
        &'a self,
        filter: &'a DatomFilter,
    ) -> Pin<Box<dyn Future<Output = Result<Vec<SignedTransactionBundle>, FerraError>> + Send + 'a>> {
        let snapshot = self.db.snapshot();
        // 1. Collect all datoms matching filter
        let matched: Vec<Datom> = snapshot.datoms()
            .filter(|d| filter.matches(d))
            .cloned()
            .collect();
        // 2. Group by TxId
        let mut groups: BTreeMap<TxId, Vec<Datom>> = BTreeMap::new();
        for datom in matched {
            groups.entry(datom.tx()).or_default().push(datom);
        }
        // 3. Also collect tx/* metadata datoms for each TxId in groups
        //    (metadata may not match the filter but must be included
        //    for bundle reconstruction)
        for tx_id in groups.keys().cloned().collect::<Vec<_>>() {
            for datom in snapshot.datoms() {
                if datom.tx() == tx_id
                    && datom.attribute().as_str().starts_with("tx/")
                    && !groups[&tx_id].iter().any(|d| d == datom)
                {
                    groups.get_mut(&tx_id).map(|v| v.push(datom.clone()));
                }
            }
        }
        // 4. Construct SignedTransactionBundle per group
        let bundles: Vec<SignedTransactionBundle> = groups.into_iter()
            .map(|(tx_id, datoms)| {
                SignedTransactionBundle::from_store_datoms(&datoms, tx_id)
            })
            .collect();
        Box::pin(std::future::ready(Ok(bundles)))
    }

    fn schema<'a>(&'a self) -> Pin<Box<dyn Future<Output = Result<Schema, FerraError>> + Send + 'a>> {
        Box::pin(std::future::ready(Ok(self.db.schema())))
    }

    fn frontier<'a>(&'a self) -> Pin<Box<dyn Future<Output = Result<Frontier, FerraError>> + Send + 'a>> {
        Box::pin(std::future::ready(Ok(self.db.frontier())))
    }

    fn ping<'a>(&'a self) -> Pin<Box<dyn Future<Output = Result<Duration, FerraError>> + Send + 'a>> {
        Box::pin(std::future::ready(Ok(Duration::ZERO)))
    }
}
```

