/// Run-length encoded entity column (INV-FERR-082).
///
/// EAVT sort guarantees entity contiguity. Store (EntityId, count) per group
/// plus prefix sums for O(1) group boundary lookup.
pub struct EntityRLE {
    /// (EntityId, count) pairs in EAVT order.
    groups: Vec<(EntityId, u32)>,
    /// Prefix sums: prefix_sum[i] = total datoms before group i.
    /// prefix_sum[0] = 0, prefix_sum[groups.len()] = total datoms.
    prefix_sum: Vec<u32>,
}

impl EntityRLE {
    /// Build from a flat entity column (EAVT-sorted, contiguous). O(N).
    pub fn from_sorted(entities: &[EntityId]) -> Self { todo!() }

    /// Start position of group at rank i in the canonical array. O(1).
    #[inline]
    pub fn group_start(&self, rank: usize) -> usize {
        self.prefix_sum[rank] as usize
    }

    /// Number of datoms for group at rank i. O(1).
    #[inline]
    pub fn group_count(&self, rank: usize) -> u32 {
        self.groups[rank].1
    }

    /// EntityId for group at rank i. O(1).
    #[inline]
    pub fn entity_at_rank(&self, rank: usize) -> EntityId {
        self.groups[rank].0
    }

    /// Which entity owns canonical position pos? O(log G).
    pub fn entity_at_position(&self, pos: usize) -> EntityId {
        let rank = self.prefix_sum.partition_point(|&s| (s as usize) <= pos) - 1;
        self.groups[rank].0
    }

    /// Total number of entity groups. O(1).
    pub fn num_groups(&self) -> usize { self.groups.len() }
}
```

