## Pseudocode — batch_replay (NEW in store/apply.rs)

```rust
impl Store {
    /// Batch WAL replay: promote once, replay all entries, demote once (INV-FERR-014).
    ///
    /// Replaces N × replay_entry() calls in Database::open recovery.
    /// Cost: 1 promote + N × insert + 1 demote, vs N × (promote + insert).
    pub fn batch_replay(&mut self, entries: &[(u64, Vec<Datom>)]) -> Result<(), FerraError> {
        if entries.is_empty() { return Ok(()); }
        self.promote(); // One-time O(n log n) — builds OrdSet + Indexes
        for (epoch, datoms) in entries {
            for datom in datoms {
                // Insert directly into OrdMap variant (already promoted)
                match &mut self.repr {
                    StoreRepr::OrdMap { datoms: d, indexes: idx } => {
                        d.insert(datom.clone());
                        idx.insert(datom);
                    }
                    StoreRepr::Positional(_) => {
                        debug_assert!(false, "batch_replay: must be OrdMap after promote");
                    }
                }
                self.live_apply(datom);
            }
            self.epoch = *epoch;
            crate::schema_evolution::evolve_schema(&mut self.schema, datoms)?;
        }
        self.demote(); // One-time O(n) — rebuilds Positional
        Ok(())
    }
}
```

