/// Generate a store with datoms drawn from a shared entity/attribute pool,
/// ensuring non-trivial overlap between independently generated stores.
pub fn arb_store_with_overlap(
    max_datoms: usize,
) -> impl Strategy<Value = (BTreeSet<Datom>, BTreeSet<Datom>)> {
    // Generate a shared pool of (entity, attribute) pairs
    let pool = prop::collection::vec(
        (arb_entity_id(), arb_attribute()),
        2..max_datoms,
    );
    // Each store draws from the pool with random values/txids
    pool.prop_flat_map(move |pool| {
        let pool_a = pool.clone();
        let pool_b = pool;
        (
            arb_store_from_pool(pool_a, max_datoms),
            arb_store_from_pool(pool_b, max_datoms),
        )
    })
}
